  1→import { Injectable } from '@nestjs/common';
  2→import { Node } from 'neo4j-driver';
  3→import { Neo4jService } from '../database/neo4j.service';
  4→import { VouchRequestDto } from './dto/vouch-request.dto';
  5→
  6→/** Internal shape returned by Neo4j — includes status for service-level 409 checks. */
  7→export interface RawVouchRequest extends VouchRequestDto {
  8→  status: 'pending' | 'confirmed' | 'declined';
  9→}
 10→
 11→function props(node: Node): Record<string, unknown> {
 12→  return node.properties as Record<string, unknown>;
 13→}
 14→
 15→@Injectable()
 16→export class VouchRepository {
 17→  constructor(private readonly neo4j: Neo4jService) {}
 18→
 19→  /** Pending requests addressed to this voucher (IDENTIFIED member). */
 20→  async getPendingRequests(voucherKeycloakId: string): Promise<VouchRequestDto[]> {
 21→    return this.neo4j.query(
 22→      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})<-[:TO]-(req:VouchRequest {status: 'pending'})-[:FROM]->(requestee:ShareMember)
 23→       RETURN req, requestee
 24→       ORDER BY req.requestedAt ASC`,
 25→      { voucherKeycloakId },
 26→      (record) => this.mapRequest(record),
 27→    );
 28→  }
 29→
 30→  /** A specific request addressed to this voucher — regardless of status (for 409 detection). */
 31→  async getRawRequest(
 32→    requestId: string,
 33→    voucherKeycloakId: string,
 34→  ): Promise<RawVouchRequest | null> {
 35→    return this.neo4j.querySingleObject(
 36→      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})<-[:TO]-(req:VouchRequest {id: $requestId})-[:FROM]->(requestee:ShareMember)
 37→       RETURN req, requestee`,
 38→      { requestId, voucherKeycloakId },
 39→      (record) => ({
 40→        ...this.mapRequest(record),
 41→        status: (record.get('req') as Node).properties['status'] as RawVouchRequest['status'],
 42→      }),
 43→    );
 44→  }
 45→
 46→  /** Returns number of active VOUCHED_FOR relationships created by this voucher. */
 47→  async countActiveVouches(voucherKeycloakId: string): Promise<number> {
 48→    const result = await this.neo4j.querySingleObject(
 49→      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})
 50→       OPTIONAL MATCH (voucher)-[:VOUCHED_FOR]->()
 51→       RETURN count(*) AS n`,
 52→      { voucherKeycloakId },
 53→      (record) => {
 54→        const v = record.get('n') as unknown;
 55→        if (typeof v === 'number') return v;
 56→        if (v !== null && typeof v === 'object' && 'toNumber' in v) {
 57→          return (v as { toNumber: () => number }).toNumber();
 58→        }
 59→        return 0;
 60→      },
 61→    );
 62→    return result ?? 0;
 63→  }
 64→
 65→  /**
 66→   * Marks request as confirmed, creates VOUCHED_FOR relationship, and sets
 67→   * requestee.eidStatus = 'identified'.
 68→   *
 69→   * Returns the requestee's keycloakId (needed for Keycloak attribute update),
 70→   * or null if the request was not found (already gone or concurrent confirm).
 71→   */
 72→  async confirmRequest(
 73→    requestId: string,
 74→    voucherKeycloakId: string,
 75→    vouchId: string,
 76→  ): Promise<string | null> {
 77→    const results = await this.neo4j.write(
 78→      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})<-[:TO]-(req:VouchRequest {id: $requestId, status: 'pending'})-[:FROM]->(requestee:ShareMember)
 79→       SET req.status = 'confirmed'
 80→       CREATE (voucher)-[:VOUCHED_FOR { id: $vouchId, vouchedAt: datetime() }]->(requestee)
 81→       SET requestee.eidStatus = 'identified'
 82→       RETURN requestee.keycloakId AS requesteeKeycloakId`,
 83→      { requestId, voucherKeycloakId, vouchId },
 84→      (record) => record.get('requesteeKeycloakId') as string,
 85→    );
 86→    return results[0] ?? null;
 87→  }
 88→
 89→  /**
 90→   * Marks request as declined.
 91→   *
 92→   * Returns true if a pending request was found and updated, false otherwise.
 93→   */
 94→  async declineRequest(requestId: string, voucherKeycloakId: string): Promise<boolean> {
 95→    const results = await this.neo4j.write(
 96→      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})<-[:TO]-(req:VouchRequest {id: $requestId, status: 'pending'})
 97→       SET req.status = 'declined'
 98→       RETURN req.id AS id`,
 99→      { requestId, voucherKeycloakId },
100→      (record) => record.get('id') as string,
101→    );
102→    return results.length > 0;
103→  }
104→
105→  /** Find IDENTIFIED ShareMember by email (via linked Shareholder emails[]). Returns keycloakId or null. */
106→  async findIdentifiedByEmail(
107→    email: string,
108→  ): Promise<{ keycloakId: string; shareMemberId: string; name: string } | null> {
109→    return this.neo4j.querySingleObject(
110→      `MATCH (sm:ShareMember {eidStatus: 'identified'})-[:IS]->(sh:Shareholder)
111→       WHERE $email IN sh.emails
112→       RETURN sm.keycloakId AS keycloakId, sm.id AS shareMemberId, sm.displayName AS displayName
113→       LIMIT 1`,
114→      { email },
115→      (record) => ({
116→        keycloakId: record.get('keycloakId') as string,
117→        shareMemberId: record.get('shareMemberId') as string,
118→        name: record.get('displayName') as string,
119→      }),
120→    );
121→  }
122→
123→  /** Returns true if a pending VouchRequest already exists from requester → target. */
124→  async hasPendingRequest(
125→    requesterKeycloakId: string,
126→    targetKeycloakId: string,
127→  ): Promise<boolean> {
128→    const result = await this.neo4j.querySingleObject(
129→      `MATCH (sm_req:ShareMember {keycloakId: $requesterKeycloakId})<-[:FROM]-(req:VouchRequest {status: 'pending'})-[:TO]->(sm_target:ShareMember {keycloakId: $targetKeycloakId})
130→       RETURN req.id AS id`,
131→      { requesterKeycloakId, targetKeycloakId },
132→      (record) => record.get('id') as string,
133→    );
134→    return result !== null;
135→  }
136→
137→  /** Creates a VouchRequest node. Returns the created DTO. */
138→  async createRequest(
139→    requesterKeycloakId: string,
140→    targetKeycloakId: string,
141→    requestId: string,
142→  ): Promise<VouchRequestDto> {
143→    const results = await this.neo4j.write(
144→      `MATCH (sm_req:ShareMember {keycloakId: $requesterKeycloakId})
145→       MATCH (sm_target:ShareMember {keycloakId: $targetKeycloakId})
146→       CREATE (req:VouchRequest {
147→         id: $requestId,
148→         requestedAt: datetime(),
149→         status: 'pending'
150→       })
151→       CREATE (req)-[:FROM]->(sm_req)
152→       CREATE (req)-[:TO]->(sm_target)
153→       RETURN req, sm_target AS requestee`,
154→      { requesterKeycloakId, targetKeycloakId, requestId },
155→      (record) => this.mapRequest(record),
156→    );
157→    return results[0];
158→  }
159→
160→  /**
161→   * Best-effort: creates VouchRequest from new member → IDENTIFIED community founder.
162→   * No-op if: member already identified, founder not found, or request already exists.
163→   */
164→  async maybeCreateInviterRequest(
165→    newMemberKeycloakId: string,
166→    communityId: string,
167→    requestId: string,
168→  ): Promise<void> {
169→    await this.neo4j.writeVoid(
170→      `MATCH (sm_new:ShareMember {keycloakId: $newMemberKeycloakId, eidStatus: 'un_identified'})
171→       MATCH (sh_founder:Shareholder)-[:FOUNDED]->(c:Community {id: $communityId})
172→       MATCH (sm_founder:ShareMember)-[:IS]->(sh_founder)
173→       WHERE sm_founder.eidStatus = 'identified'
174→       WITH sm_new, sm_founder LIMIT 1
175→       OPTIONAL MATCH (existing:VouchRequest {status: 'pending'})-[:FROM]->(sm_new), (existing)-[:TO]->(sm_founder)
176→       WITH sm_new, sm_founder, existing
177→       WHERE existing IS NULL
178→       CREATE (req:VouchRequest { id: $requestId, requestedAt: datetime(), status: 'pending' })
179→       CREATE (req)-[:FROM]->(sm_new)
180→       CREATE (req)-[:TO]->(sm_founder)`,
181→      { newMemberKeycloakId, communityId, requestId },
182→    );
183→  }
184→
185→  private mapRequest(record: { get: (key: string) => unknown }): VouchRequestDto {
186→    const req = props(record.get('req') as Node);
187→    const requestee = props(record.get('requestee') as Node);
188→    return {
189→      id: req['id'] as string,
190→      requestedAt: req['requestedAt'] as string,
191→      requestee: {
192→        shareMemberId: requestee['id'] as string,
193→        name: requestee['displayName'] as string,
194→        pictureUrl: null, // Served from MinIO — client constructs URL from shareMemberId
195→      },
196→    };
197→  }
198→}
199→

  1→import {
  2→  BadRequestException,
  3→  ConflictException,
  4→  ForbiddenException,
  5→  Injectable,
  6→  Logger,
  7→  NotFoundException,
  8→} from '@nestjs/common';
  9→import * as crypto from 'crypto';
 10→import { EidService } from '../eid/eid.service';
 11→import { VouchRequestDto } from './dto/vouch-request.dto';
 12→import { VouchRepository } from './vouch.repository';
 13→
 14→const MAX_ACTIVE_VOUCHES = 3;
 15→
 16→@Injectable()
 17→export class VouchService {
 18→  private readonly logger = new Logger(VouchService.name);
 19→
 20→  constructor(
 21→    private readonly repository: VouchRepository,
 22→    private readonly eidService: EidService,
 23→  ) {}
 24→
 25→  async getPendingRequests(voucherKeycloakId: string): Promise<VouchRequestDto[]> {
 26→    return this.repository.getPendingRequests(voucherKeycloakId);
 27→  }
 28→
 29→  async getRequest(requestId: string, voucherKeycloakId: string): Promise<VouchRequestDto> {
 30→    const raw = await this.repository.getRawRequest(requestId, voucherKeycloakId);
 31→    if (!raw) throw new NotFoundException('Vouch request not found.');
 32→    if (raw.status !== 'pending') throw new ConflictException('Vouch request already processed.');
 33→    return { id: raw.id, requestedAt: raw.requestedAt, requestee: raw.requestee };
 34→  }
 35→
 36→  async confirm(requestId: string, voucherKeycloakId: string): Promise<void> {
 37→    const raw = await this.repository.getRawRequest(requestId, voucherKeycloakId);
 38→    if (!raw) throw new NotFoundException('Vouch request not found.');
 39→    if (raw.status !== 'pending') throw new ConflictException('Vouch request already processed.');
 40→
 41→    const activeCount = await this.repository.countActiveVouches(voucherKeycloakId);
 42→    if (activeCount >= MAX_ACTIVE_VOUCHES) {
 43→      throw new ForbiddenException(
 44→        `Maximum active vouches reached (${MAX_ACTIVE_VOUCHES}). You must wait for an existing vouch to be superseded before confirming another.`,
 45→      );
 46→    }
 47→
 48→    const vouchId = crypto.randomUUID();
 49→    const requesteeKeycloakId = await this.repository.confirmRequest(
 50→      requestId,
 51→      voucherKeycloakId,
 52→      vouchId,
 53→    );
 54→
 55→    if (requesteeKeycloakId) {
 56→      // Best-effort: update Keycloak so the next token refresh includes eid_status = identified
 57→      await this.eidService.updateKeycloakEidStatus(requesteeKeycloakId);
 58→    } else {
 59→      this.logger.warn(
 60→        `confirm: request ${requestId} was valid but write returned no rows (concurrent confirm?)`,
 61→      );
 62→    }
 63→  }
 64→
 65→  async decline(requestId: string, voucherKeycloakId: string): Promise<void> {
 66→    const raw = await this.repository.getRawRequest(requestId, voucherKeycloakId);
 67→    if (!raw) throw new NotFoundException('Vouch request not found.');
 68→    if (raw.status !== 'pending') throw new ConflictException('Vouch request already processed.');
 69→
 70→    await this.repository.declineRequest(requestId, voucherKeycloakId);
 71→  }
 72→
 73→  async createRequest(
 74→    requesterKeycloakId: string,
 75→    requesterEidStatus: string | undefined,
 76→    targetEmail: string,
 77→  ): Promise<VouchRequestDto> {
 78→    if (requesterEidStatus === 'identified') {
 79→      throw new BadRequestException('Already identified — vouching not needed.');
 80→    }
 81→
 82→    const target = await this.repository.findIdentifiedByEmail(targetEmail);
 83→    if (!target) {
 84→      throw new NotFoundException('No IDENTIFIED member found with that email.');
 85→    }
 86→
 87→    const alreadyPending = await this.repository.hasPendingRequest(
 88→      requesterKeycloakId,
 89→      target.keycloakId,
 90→    );
 91→    if (alreadyPending) {
 92→      throw new ConflictException('A pending vouch request to this member already exists.');
 93→    }
 94→
 95→    const requestId = crypto.randomUUID();
 96→    return this.repository.createRequest(requesterKeycloakId, target.keycloakId, requestId);
 97→  }
 98→
 99→  async createInviterRequest(newMemberKeycloakId: string, communityId: string): Promise<void> {
100→    try {
101→      const requestId = crypto.randomUUID();
102→      await this.repository.maybeCreateInviterRequest(newMemberKeycloakId, communityId, requestId);
103→    } catch (err) {
104→      this.logger.warn(
105→        `createInviterRequest: best-effort failed for member ${newMemberKeycloakId} in community ${communityId}: ${String(err)}`,
106→      );
107→    }
108→  }
109→}
110→

 1→import {
 2→  Body,
 3→  Controller,
 4→  Get,
 5→  HttpCode,
 6→  HttpStatus,
 7→  Param,
 8→  Post,
 9→  UseGuards,
10→} from '@nestjs/common';
11→import { IsEmail, IsNotEmpty } from 'class-validator';
12→import { KeycloakAuthGuard } from '../common/guards/keycloak-auth.guard';
13→import { CurrentUser } from '../common/decorators/current-user.decorator';
14→import * as SharememberTypes from '../common/interfaces/sharemember-token.interface';
15→type SharememberToken = SharememberTypes.SharememberToken;
16→import { VouchService } from './vouch.service';
17→import { VouchRequestDto } from './dto/vouch-request.dto';
18→
19→class CreateVouchRequestBody {
20→  @IsEmail()
21→  @IsNotEmpty()
22→  targetEmail!: string;
23→}
24→
25→/**
26→ * Peer vouching endpoints — identity layer, not community-scoped.
27→ * Addressed to the IDENTIFIED member who is asked to confirm another's identity.
28→ */
29→@Controller('v2/sharemember/vouch-requests')
30→@UseGuards(KeycloakAuthGuard)
31→export class VouchController {
32→  constructor(private readonly service: VouchService) {}
33→
34→  /** POST /v2/sharemember/vouch-requests — create a vouch request by target email */
35→  @Post()
36→  @HttpCode(HttpStatus.CREATED)
37→  async createRequest(
38→    @Body() body: CreateVouchRequestBody,
39→    @CurrentUser() user: SharememberToken,
40→  ): Promise<VouchRequestDto> {
41→    return this.service.createRequest(user.sub, user.eid_status, body.targetEmail);
42→  }
43→
44→  /** GET /v2/sharemember/vouch-requests — pending requests addressed to me */
45→  @Get()
46→  async getPendingRequests(
47→    @CurrentUser() user: SharememberToken,
48→  ): Promise<VouchRequestDto[]> {
49→    return this.service.getPendingRequests(user.sub);
50→  }
51→
52→  /** GET /v2/sharemember/vouch-requests/:requestId — single request addressed to me */
53→  @Get(':requestId')
54→  async getRequest(
55→    @Param('requestId') requestId: string,
56→    @CurrentUser() user: SharememberToken,
57→  ): Promise<VouchRequestDto> {
58→    return this.service.getRequest(requestId, user.sub);
59→  }
60→
61→  /** POST /v2/sharemember/vouch-requests/:requestId/confirm — confirm identity */
62→  @Post(':requestId/confirm')
63→  @HttpCode(HttpStatus.NO_CONTENT)
64→  async confirm(
65→    @Param('requestId') requestId: string,
66→    @CurrentUser() user: SharememberToken,
67→  ): Promise<void> {
68→    return this.service.confirm(requestId, user.sub);
69→  }
70→
71→  /** POST /v2/sharemember/vouch-requests/:requestId/decline — decline request */
72→  @Post(':requestId/decline')
73→  @HttpCode(HttpStatus.NO_CONTENT)
74→  async decline(
75→    @Param('requestId') requestId: string,
76→    @CurrentUser() user: SharememberToken,
77→  ): Promise<void> {
78→    return this.service.decline(requestId, user.sub);
79→  }
80→}
