  1→import {
  2→  BadRequestException,
  3→  ConflictException,
  4→  ForbiddenException,
  5→  NotFoundException,
  6→} from '@nestjs/common';
  7→import { EidService } from '../eid/eid.service';
  8→import { VouchRepository } from './vouch.repository';
  9→import { VouchService } from './vouch.service';
 10→import { VouchRequestDto } from './dto/vouch-request.dto';
 11→
 12→const VOUCHER_KC_ID = 'voucher-kc-1';
 13→const REQUESTER_KC_ID = 'requester-kc-1';
 14→const REQUEST_ID = 'req-uuid-1';
 15→const TARGET_EMAIL = 'anna@example.com';
 16→
 17→const identifiedTarget = {
 18→  keycloakId: 'target-kc-1',
 19→  shareMemberId: 'sm-target-1',
 20→  name: 'Anna Weber',
 21→};
 22→
 23→const pendingRequest = {
 24→  id: REQUEST_ID,
 25→  requestedAt: '2026-03-01T10:00:00Z',
 26→  status: 'pending' as const,
 27→  requestee: {
 28→    shareMemberId: 'sm-requestee-1',
 29→    name: 'Anna Weber',
 30→    pictureUrl: null,
 31→  },
 32→};
 33→
 34→const pendingDto: VouchRequestDto = {
 35→  id: pendingRequest.id,
 36→  requestedAt: pendingRequest.requestedAt,
 37→  requestee: pendingRequest.requestee,
 38→};
 39→
 40→describe('VouchService', () => {
 41→  let service: VouchService;
 42→  let repository: jest.Mocked<VouchRepository>;
 43→  let eidService: jest.Mocked<Pick<EidService, 'updateKeycloakEidStatus'>>;
 44→
 45→  beforeEach(() => {
 46→    repository = {
 47→      getPendingRequests: jest.fn(),
 48→      getRawRequest: jest.fn(),
 49→      countActiveVouches: jest.fn(),
 50→      confirmRequest: jest.fn(),
 51→      declineRequest: jest.fn(),
 52→      findIdentifiedByEmail: jest.fn(),
 53→      hasPendingRequest: jest.fn(),
 54→      createRequest: jest.fn(),
 55→      maybeCreateInviterRequest: jest.fn(),
 56→    } as unknown as jest.Mocked<VouchRepository>;
 57→
 58→    eidService = {
 59→      updateKeycloakEidStatus: jest.fn().mockResolvedValue(undefined),
 60→    } as unknown as jest.Mocked<Pick<EidService, 'updateKeycloakEidStatus'>>;
 61→
 62→    service = new VouchService(repository, eidService as unknown as EidService);
 63→  });
 64→
 65→  describe('getPendingRequests', () => {
 66→    it('delegates to repository', async () => {
 67→      repository.getPendingRequests.mockResolvedValue([pendingDto]);
 68→      const result = await service.getPendingRequests(VOUCHER_KC_ID);
 69→      expect(result).toEqual([pendingDto]);
 70→      expect(repository.getPendingRequests).toHaveBeenCalledWith(VOUCHER_KC_ID);
 71→    });
 72→
 73→    it('returns empty array when no pending requests', async () => {
 74→      repository.getPendingRequests.mockResolvedValue([]);
 75→      expect(await service.getPendingRequests(VOUCHER_KC_ID)).toEqual([]);
 76→    });
 77→  });
 78→
 79→  describe('getRequest', () => {
 80→    it('returns DTO for a pending request', async () => {
 81→      repository.getRawRequest.mockResolvedValue(pendingRequest);
 82→      const result = await service.getRequest(REQUEST_ID, VOUCHER_KC_ID);
 83→      expect(result.id).toBe(REQUEST_ID);
 84→      expect(result.requestee.name).toBe('Anna Weber');
 85→    });
 86→
 87→    it('throws 404 when request not found', async () => {
 88→      repository.getRawRequest.mockResolvedValue(null);
 89→      await expect(service.getRequest(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(NotFoundException);
 90→    });
 91→
 92→    it('throws 409 when request already confirmed', async () => {
 93→      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'confirmed' });
 94→      await expect(service.getRequest(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
 95→    });
 96→
 97→    it('throws 409 when request already declined', async () => {
 98→      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'declined' });
 99→      await expect(service.getRequest(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
100→    });
101→  });
102→
103→  describe('confirm', () => {
104→    it('confirms a pending request and triggers Keycloak update', async () => {
105→      repository.getRawRequest.mockResolvedValue(pendingRequest);
106→      repository.countActiveVouches.mockResolvedValue(0);
107→      repository.confirmRequest.mockResolvedValue('requestee-kc-1');
108→
109→      await service.confirm(REQUEST_ID, VOUCHER_KC_ID);
110→
111→      expect(repository.confirmRequest).toHaveBeenCalledWith(
112→        REQUEST_ID,
113→        VOUCHER_KC_ID,
114→        expect.any(String),
115→      );
116→      expect(eidService.updateKeycloakEidStatus).toHaveBeenCalledWith('requestee-kc-1');
117→    });
118→
119→    it('throws 404 when request not found', async () => {
120→      repository.getRawRequest.mockResolvedValue(null);
121→      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(NotFoundException);
122→      expect(repository.confirmRequest).not.toHaveBeenCalled();
123→    });
124→
125→    it('throws 409 when request already processed', async () => {
126→      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'confirmed' });
127→      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
128→    });
129→
130→    it('throws 403 when voucher has reached 3 active vouches', async () => {
131→      repository.getRawRequest.mockResolvedValue(pendingRequest);
132→      repository.countActiveVouches.mockResolvedValue(3);
133→
134→      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ForbiddenException);
135→      expect(repository.confirmRequest).not.toHaveBeenCalled();
136→    });
137→
138→    it('allows confirm at exactly 2 active vouches (below cap)', async () => {
139→      repository.getRawRequest.mockResolvedValue(pendingRequest);
140→      repository.countActiveVouches.mockResolvedValue(2);
141→      repository.confirmRequest.mockResolvedValue('requestee-kc-1');
142→
143→      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).resolves.toBeUndefined();
144→    });
145→  });
146→
147→  describe('decline', () => {
148→    it('declines a pending request', async () => {
149→      repository.getRawRequest.mockResolvedValue(pendingRequest);
150→      repository.declineRequest.mockResolvedValue(true);
151→
152→      await service.decline(REQUEST_ID, VOUCHER_KC_ID);
153→
154→      expect(repository.declineRequest).toHaveBeenCalledWith(REQUEST_ID, VOUCHER_KC_ID);
155→      expect(eidService.updateKeycloakEidStatus).not.toHaveBeenCalled();
156→    });
157→
158→    it('throws 404 when request not found', async () => {
159→      repository.getRawRequest.mockResolvedValue(null);
160→      await expect(service.decline(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(NotFoundException);
161→    });
162→
163→    it('throws 409 when request already processed', async () => {
164→      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'declined' });
165→      await expect(service.decline(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
166→    });
167→  });
168→
169→  describe('createRequest', () => {
170→    const createdDto: VouchRequestDto = {
