 1→import { Injectable, NotFoundException, BadRequestException, ForbiddenException } from '@nestjs/common';
 2→import { SharememberRepository } from './sharemember.repository';
 3→import { CommunityService } from '../community/community.service';
 4→import { VouchService } from './vouch.service';
 5→import {
 6→  CommunityTeaserDto,
 7→  JoinCommunityResponseDto,
 8→  PublicCommunityTeaserDto,
 9→} from './dto/community-teaser.dto';
10→
11→@Injectable()
12→export class SharememberService {
13→  constructor(
14→    private readonly repository: SharememberRepository,
15→    private readonly communityService: CommunityService,
16→    private readonly vouchService: VouchService,
17→  ) {}
18→
19→  async getCommunitiesForShareholder(
20→    shareholderId: string,
21→  ): Promise<CommunityTeaserDto[]> {
22→    return this.repository.getCommunitiesForShareholder(shareholderId);
23→  }
24→
25→  async discoverCommunities(
26→    shareholderId: string,
27→  ): Promise<PublicCommunityTeaserDto[]> {
28→    return this.repository.findPublicCommunities(shareholderId);
29→  }
30→
31→  async joinOpenCommunity(
32→    shareholderId: string,
33→    communityId: string,
34→  ): Promise<JoinCommunityResponseDto> {
35→    const community = await this.communityService.getById(communityId);
36→    if (!community) throw new NotFoundException('Community not found');
37→    if (!community.isPublic) throw new ForbiddenException('Community is not public');
38→    if (community.inviteCode) throw new ForbiddenException('Community requires an invite code');
39→
40→    const result = await this.repository.joinCommunity(shareholderId, communityId);
41→    void this.vouchService.createInviterRequest(shareholderId, communityId).catch(() => {});
42→    return result;
43→  }
44→
45→  async joinCommunity(
46→    shareholderId: string,
47→    inviteCode: string,
48→  ): Promise<JoinCommunityResponseDto> {
49→    const trimmed = inviteCode.trim();
50→    if (!trimmed) {
51→      throw new BadRequestException('Invite code must not be blank.');
52→    }
53→
54→    const community =
55→      await this.repository.findCommunityByInviteCode(trimmed);
56→    if (!community) {
57→      throw new NotFoundException('Invalid invite code.');
58→    }
59→
60→    const result = await this.repository.joinCommunity(shareholderId, community.id);
61→    void this.vouchService.createInviterRequest(shareholderId, community.id).catch(() => {});
62→    return result;
63→  }
64→}
