  1→import { Injectable } from '@nestjs/common';
  2→import { Node, Record as Neo4jRecord } from 'neo4j-driver';
  3→import { Neo4jService } from '../database/neo4j.service';
  4→import {
  5→  CommunityTeaserDto,
  6→  JoinCommunityResponseDto,
  7→  PublicCommunityTeaserDto,
  8→} from './dto/community-teaser.dto';
  9→
 10→function props(node: Node): Record<string, unknown> {
 11→  return node.properties as Record<string, unknown>;
 12→}
 13→
 14→function toNumber(value: unknown): number {
 15→  if (typeof value === 'number') return value;
 16→  if (
 17→    value !== null &&
 18→    typeof value === 'object' &&
 19→    'toNumber' in value &&
 20→    typeof (value as { toNumber: unknown }).toNumber === 'function'
 21→  ) {
 22→    return (value as { toNumber: () => number }).toNumber();
 23→  }
 24→  return 0;
 25→}
 26→
 27→@Injectable()
 28→export class SharememberRepository {
 29→  constructor(private readonly neo4j: Neo4jService) {}
 30→
 31→  async getCommunitiesForShareholder(
 32→    shareholderId: string,
 33→  ): Promise<CommunityTeaserDto[]> {
 34→    return this.neo4j.query(
 35→      `MATCH (sh:Shareholder {id: $shareholderId})-[:MEMBER_OF]->(c:Community)
 36→       OPTIONAL MATCH (rt:Roundtable)-[r:FORMED_FOR]->(c) WHERE r.validUntil IS NULL
 37→       WITH c, rt
 38→       OPTIONAL MATCH ()-[:MEMBER_OF]->(c)
 39→       RETURN c, rt, count(*) AS memberCount`,
 40→      { shareholderId },
 41→      (record) => this.mapTeaser(record),
 42→    );
 43→  }
 44→
 45→  async findPublicCommunities(
 46→    shareholderId: string,
 47→  ): Promise<PublicCommunityTeaserDto[]> {
 48→    return this.neo4j.query(
 49→      `MATCH (c:Community {isPublic: true})
 50→       OPTIONAL MATCH ()-[:MEMBER_OF]->(c)
 51→       WITH c, count(*) AS memberCount
 52→       OPTIONAL MATCH (sh:Shareholder {id: $shareholderId})-[:MEMBER_OF]->(c)
 53→       RETURN c,
 54→              memberCount,
 55→              sh IS NOT NULL AS isMember,
 56→              c.inviteCode IS NOT NULL AS hasInviteCode`,
 57→      { shareholderId },
 58→      (record) => {
 59→        const p = (record.get('c') as Node).properties as Record<string, unknown>;
 60→        return {
 61→          id: p.id as string,
 62→          name: p.name as string,
 63→          intent: (p.intent as string) ?? null,
 64→          logoUrl: (p.logoUrl as string) ?? null,
 65→          memberCount: toNumber(record.get('memberCount')),
 66→          isMember: record.get('isMember') as boolean,
 67→          hasInviteCode: record.get('hasInviteCode') as boolean,
 68→        };
 69→      },
 70→    );
 71→  }
 72→
 73→  /** Finds a community by invite code (comma-separated codes on Community.inviteCode). */
 74→  async findCommunityByInviteCode(
 75→    inviteCode: string,
 76→  ): Promise<{ id: string; name: string; frontendUrl: string | null } | null> {
 77→    return this.neo4j.querySingleObject(
 78→      `MATCH (c:Community)
 79→       WHERE c.inviteCode IS NOT NULL
 80→         AND any(code IN split(c.inviteCode, ',') WHERE trim(code) = $inviteCode)
 81→       RETURN c`,
 82→      { inviteCode },
 83→      (record) => {
 84→        const p = props(record.get('c') as Node);
 85→        return {
 86→          id: p.id as string,
 87→          name: p.name as string,
 88→          frontendUrl: (p.frontendUrl as string) ?? null,
 89→        };
 90→      },
 91→    );
 92→  }
 93→
 94→  /** Creates Shareholder if not exists and adds MEMBER_OF relationship. Idempotent. */
 95→  async joinCommunity(
 96→    shareholderId: string,
 97→    communityId: string,
 98→  ): Promise<JoinCommunityResponseDto> {
 99→    const results = await this.neo4j.write(
100→      `MATCH (c:Community {id: $communityId})
101→       MERGE (sh:Shareholder {id: $shareholderId})
102→       MERGE (sh)-[:MEMBER_OF]->(c)
103→       RETURN c.id AS communityId, c.name AS communityName, c.frontendUrl AS frontendUrl`,
104→      { shareholderId, communityId },
105→      (record) => ({
106→        communityId: record.get('communityId') as string,
107→        communityName: record.get('communityName') as string,
108→        frontendUrl: (record.get('frontendUrl') as string) ?? null,
109→      }),
110→    );
111→    return results[0]!;
112→  }
113→
114→  private mapTeaser(record: Neo4jRecord): CommunityTeaserDto {
115→    const c = record.get('c') as Node;
116→    const rt = record.get('rt') as Node | null;
117→    const cp = props(c);
118→
119→    return {
120→      id: cp.id as string,
121→      name: cp.name as string,
122→      intent: (cp.intent as string) ?? null,
123→      frontendUrl: (cp.frontendUrl as string) ?? null,
124→      logoUrl: (cp.logoUrl as string) ?? null,
125→      memberCount: toNumber(record.get('memberCount')),
126→      purposeRoundtable: rt
127→        ? (() => {
128→            const rp = props(rt);
129→            return {
130→              id: rp.id as string,
131→              name: rp.name as string,
132→              intent: (rp.intent as string) ?? '',
133→            };
134→          })()
135→        : null,
136→    };
137→  }
138→}
