164→  async maybeCreateInviterRequest(
165→    newMemberKeycloakId: string,
166→    communityId: string,
167→    requestId: string,
168→  ): Promise<void> {
169→    await this.neo4j.writeVoid(
170→      `MATCH (sm_new:ShareMember {keycloakId: $newMemberKeycloakId, eidStatus: 'un_identified'})
171→       MATCH (sh_founder:Shareholder)-[:FOUNDED]->(c:Community {id: $communityId})
172→       MATCH (sm_founder:ShareMember)-[:IS]->(sh_founder)
173→       WHERE sm_founder.eidStatus = 'identified'
174→       WITH sm_new, sm_founder LIMIT 1
175→       OPTIONAL MATCH (existing:VouchRequest {status: 'pending'})-[:FROM]->(sm_new), (existing)-[:TO]->(sm_founder)
176→       WITH sm_new, sm_founder, existing
177→       WHERE existing IS NULL
178→       CREATE (req:VouchRequest { id: $requestId, requestedAt: datetime(), status: 'pending' })
179→       CREATE (req)-[:FROM]->(sm_new)
180→       CREATE (req)-[:TO]->(sm_founder)`,
181→      { newMemberKeycloakId, communityId, requestId },
182→    );
183→  }
184→
185→  private mapRequest(record: { get: (key: string) => unknown }): VouchRequestDto {
186→    const req = props(record.get('req') as Node);
187→    const requestee = props(record.get('requestee') as Node);
188→    return {
189→      id: req['id'] as string,
190→      requestedAt: req['requestedAt'] as string,
191→      requestee: {
192→        shareMemberId: requestee['id'] as string,
193→        name: requestee['displayName'] as string,
194→        pictureUrl: null, // Served from MinIO — client constructs URL from shareMemberId
195→      },
196→    };
197→  }
