import { Injectable } from '@nestjs/common';
import { Node } from 'neo4j-driver';
import { Neo4jService } from '../database/neo4j.service';
import { VouchRequestDto } from './dto/vouch-request.dto';

/** Internal shape returned by Neo4j — includes status for service-level 409 checks. */
export interface RawVouchRequest extends VouchRequestDto {
  status: 'pending' | 'confirmed' | 'declined';
}

function props(node: Node): Record<string, unknown> {
  return node.properties as Record<string, unknown>;
}

@Injectable()
export class VouchRepository {
  constructor(private readonly neo4j: Neo4jService) {}

  /** Pending requests addressed to this voucher (IDENTIFIED member). */
  async getPendingRequests(voucherKeycloakId: string): Promise<VouchRequestDto[]> {
    return this.neo4j.query(
      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})<-[:TO]-(req:VouchRequest {status: 'pending'})-[:FROM]->(requestee:ShareMember)
       RETURN req, requestee
       ORDER BY req.requestedAt ASC`,
      { voucherKeycloakId },
      (record) => this.mapRequest(record),
    );
  }

  /** A specific request addressed to this voucher — regardless of status (for 409 detection). */
  async getRawRequest(
    requestId: string,
    voucherKeycloakId: string,
  ): Promise<RawVouchRequest | null> {
    return this.neo4j.querySingleObject(
      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})<-[:TO]-(req:VouchRequest {id: $requestId})-[:FROM]->(requestee:ShareMember)
       RETURN req, requestee`,
      { requestId, voucherKeycloakId },
      (record) => ({
        ...this.mapRequest(record),
        status: (record.get('req') as Node).properties['status'] as RawVouchRequest['status'],
      }),
    );
  }

  /** Returns number of active VOUCHED_FOR relationships created by this voucher. */
  async countActiveVouches(voucherKeycloakId: string): Promise<number> {
    const result = await this.neo4j.querySingleObject(
      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})
       OPTIONAL MATCH (voucher)-[:VOUCHED_FOR]->()
       RETURN count(*) AS n`,
      { voucherKeycloakId },
      (record) => {
        const v = record.get('n') as unknown;
        if (typeof v === 'number') return v;
        if (v !== null && typeof v === 'object' && 'toNumber' in v) {
          return (v as { toNumber: () => number }).toNumber();
        }
        return 0;
      },
    );
    return result ?? 0;
  }

  /**
   * Marks request as confirmed, creates VOUCHED_FOR relationship, and sets
   * requestee.eidStatus = 'identified'.
   *
   * Returns the requestee's keycloakId (needed for Keycloak attribute update),
   * or null if the request was not found (already gone or concurrent confirm).
   */
  async confirmRequest(
    requestId: string,
    voucherKeycloakId: string,
    vouchId: string,
  ): Promise<string | null> {
    const results = await this.neo4j.write(
      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})<-[:TO]-(req:VouchRequest {id: $requestId, status: 'pending'})-[:FROM]->(requestee:ShareMember)
       SET req.status = 'confirmed'
       CREATE (voucher)-[:VOUCHED_FOR { id: $vouchId, vouchedAt: datetime() }]->(requestee)
       SET requestee.eidStatus = 'identified'
       RETURN requestee.keycloakId AS requesteeKeycloakId`,
      { requestId, voucherKeycloakId, vouchId },
      (record) => record.get('requesteeKeycloakId') as string,
    );
    return results[0] ?? null;
  }

  /**
   * Marks request as declined.
   *
   * Returns true if a pending request was found and updated, false otherwise.
   */
  async declineRequest(requestId: string, voucherKeycloakId: string): Promise<boolean> {
    const results = await this.neo4j.write(
      `MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})<-[:TO]-(req:VouchRequest {id: $requestId, status: 'pending'})
       SET req.status = 'declined'
       RETURN req.id AS id`,
      { requestId, voucherKeycloakId },
      (record) => record.get('id') as string,
    );
    return results.length > 0;
  }

  /** Find IDENTIFIED ShareMember by email (via linked Shareholder emails[]). Returns keycloakId or null. */
  async findIdentifiedByEmail(
    email: string,
  ): Promise<{ keycloakId: string; shareMemberId: string; name: string } | null> {
    return this.neo4j.querySingleObject(
      `MATCH (sm:ShareMember {eidStatus: 'identified'})-[:IS]->(sh:Shareholder)
       WHERE $email IN sh.emails
       RETURN sm.keycloakId AS keycloakId, sm.id AS shareMemberId, sm.displayName AS displayName
       LIMIT 1`,
      { email },
      (record) => ({
        keycloakId: record.get('keycloakId') as string,
        shareMemberId: record.get('shareMemberId') as string,
        name: record.get('displayName') as string,
      }),
    );
  }

  /** Returns true if a pending VouchRequest already exists from requester → target. */
  async hasPendingRequest(
    requesterKeycloakId: string,
    targetKeycloakId: string,
  ): Promise<boolean> {
    const result = await this.neo4j.querySingleObject(
      `MATCH (sm_req:ShareMember {keycloakId: $requesterKeycloakId})<-[:FROM]-(req:VouchRequest {status: 'pending'})-[:TO]->(sm_target:ShareMember {keycloakId: $targetKeycloakId})
       RETURN req.id AS id`,
      { requesterKeycloakId, targetKeycloakId },
      (record) => record.get('id') as string,
    );
    return result !== null;
  }

  /** Creates a VouchRequest node. Returns the created DTO. */
  async createRequest(
    requesterKeycloakId: string,
    targetKeycloakId: string,
    requestId: string,
  ): Promise<VouchRequestDto> {
    const results = await this.neo4j.write(
      `MATCH (sm_req:ShareMember {keycloakId: $requesterKeycloakId})
       MATCH (sm_target:ShareMember {keycloakId: $targetKeycloakId})
       CREATE (req:VouchRequest {
         id: $requestId,
         requestedAt: datetime(),
         status: 'pending'
       })
       CREATE (req)-[:FROM]->(sm_req)
       CREATE (req)-[:TO]->(sm_target)
       RETURN req, sm_target AS requestee`,
      { requesterKeycloakId, targetKeycloakId, requestId },
      (record) => this.mapRequest(record),
    );
    return results[0];
  }

  /**
   * Best-effort: creates VouchRequest from new member → IDENTIFIED community founder.
   * No-op if: member already identified, founder not found, or request already exists.
   */
  async maybeCreateInviterRequest(
    newMemberKeycloakId: string,
    communityId: string,
    requestId: string,
  ): Promise<void> {
    await this.neo4j.writeVoid(
      `MATCH (sm_new:ShareMember {keycloakId: $newMemberKeycloakId, eidStatus: 'un_identified'})
       MATCH (sh_founder:Shareholder)-[:FOUNDED]->(c:Community {id: $communityId})
       MATCH (sm_founder:ShareMember)-[:IS]->(sh_founder)
       WHERE sm_founder.eidStatus = 'identified'
       WITH sm_new, sm_founder LIMIT 1
       OPTIONAL MATCH (existing:VouchRequest {status: 'pending'})-[:FROM]->(sm_new), (existing)-[:TO]->(sm_founder)
       WITH sm_new, sm_founder, existing
       WHERE existing IS NULL
       CREATE (req:VouchRequest { id: $requestId, requestedAt: datetime(), status: 'pending' })
       CREATE (req)-[:FROM]->(sm_new)
       CREATE (req)-[:TO]->(sm_founder)`,
      { newMemberKeycloakId, communityId, requestId },
    );
  }

  private mapRequest(record: { get: (key: string) => unknown }): VouchRequestDto {
    const req = props(record.get('req') as Node);
    const requestee = props(record.get('requestee') as Node);
    return {
      id: req['id'] as string,
      requestedAt: req['requestedAt'] as string,
      requestee: {
        shareMemberId: requestee['id'] as string,
        name: requestee['displayName'] as string,
        pictureUrl: null, // Served from MinIO — client constructs URL from shareMemberId
      },
    };
  }
}

