import {
  BadRequestException,
  ConflictException,
  ForbiddenException,
  NotFoundException,
} from '@nestjs/common';
import { EidService } from '../eid/eid.service';
import { VouchRepository } from './vouch.repository';
import { VouchService } from './vouch.service';
import { VouchRequestDto } from './dto/vouch-request.dto';

const VOUCHER_KC_ID = 'voucher-kc-1';
const REQUESTER_KC_ID = 'requester-kc-1';
const REQUEST_ID = 'req-uuid-1';
const TARGET_EMAIL = 'anna@example.com';

const identifiedTarget = {
  keycloakId: 'target-kc-1',
  shareMemberId: 'sm-target-1',
  name: 'Anna Weber',
};

const pendingRequest = {
  id: REQUEST_ID,
  requestedAt: '2026-03-01T10:00:00Z',
  status: 'pending' as const,
  requestee: {
    shareMemberId: 'sm-requestee-1',
    name: 'Anna Weber',
    pictureUrl: null,
  },
};

const pendingDto: VouchRequestDto = {
  id: pendingRequest.id,
  requestedAt: pendingRequest.requestedAt,
  requestee: pendingRequest.requestee,
};

describe('VouchService', () => {
  let service: VouchService;
  let repository: jest.Mocked<VouchRepository>;
  let eidService: jest.Mocked<Pick<EidService, 'updateKeycloakEidStatus'>>;

  beforeEach(() => {
    repository = {
      getPendingRequests: jest.fn(),
      getRawRequest: jest.fn(),
      countActiveVouches: jest.fn(),
      confirmRequest: jest.fn(),
      declineRequest: jest.fn(),
      findIdentifiedByEmail: jest.fn(),
      hasPendingRequest: jest.fn(),
      createRequest: jest.fn(),
      maybeCreateInviterRequest: jest.fn(),
    } as unknown as jest.Mocked<VouchRepository>;

    eidService = {
      updateKeycloakEidStatus: jest.fn().mockResolvedValue(undefined),
    } as unknown as jest.Mocked<Pick<EidService, 'updateKeycloakEidStatus'>>;

    service = new VouchService(repository, eidService as unknown as EidService);
  });

  describe('getPendingRequests', () => {
    it('delegates to repository', async () => {
      repository.getPendingRequests.mockResolvedValue([pendingDto]);
      const result = await service.getPendingRequests(VOUCHER_KC_ID);
      expect(result).toEqual([pendingDto]);
      expect(repository.getPendingRequests).toHaveBeenCalledWith(VOUCHER_KC_ID);
    });

    it('returns empty array when no pending requests', async () => {
      repository.getPendingRequests.mockResolvedValue([]);
      expect(await service.getPendingRequests(VOUCHER_KC_ID)).toEqual([]);
    });
  });

  describe('getRequest', () => {
    it('returns DTO for a pending request', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      const result = await service.getRequest(REQUEST_ID, VOUCHER_KC_ID);
      expect(result.id).toBe(REQUEST_ID);
      expect(result.requestee.name).toBe('Anna Weber');
    });

    it('throws 404 when request not found', async () => {
      repository.getRawRequest.mockResolvedValue(null);
      await expect(service.getRequest(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(NotFoundException);
    });

    it('throws 409 when request already confirmed', async () => {
      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'confirmed' });
      await expect(service.getRequest(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
    });

    it('throws 409 when request already declined', async () => {
      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'declined' });
      await expect(service.getRequest(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
    });
  });

  describe('confirm', () => {
    it('confirms a pending request and triggers Keycloak update', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      repository.countActiveVouches.mockResolvedValue(0);
      repository.confirmRequest.mockResolvedValue('requestee-kc-1');

      await service.confirm(REQUEST_ID, VOUCHER_KC_ID);

      expect(repository.confirmRequest).toHaveBeenCalledWith(
        REQUEST_ID,
        VOUCHER_KC_ID,
        expect.any(String),
      );
      expect(eidService.updateKeycloakEidStatus).toHaveBeenCalledWith('requestee-kc-1');
    });

    it('throws 404 when request not found', async () => {
      repository.getRawRequest.mockResolvedValue(null);
      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(NotFoundException);
      expect(repository.confirmRequest).not.toHaveBeenCalled();
    });

    it('throws 409 when request already processed', async () => {
      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'confirmed' });
      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
    });

    it('throws 403 when voucher has reached 3 active vouches', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      repository.countActiveVouches.mockResolvedValue(3);

      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ForbiddenException);
      expect(repository.confirmRequest).not.toHaveBeenCalled();
    });

    it('allows confirm at exactly 2 active vouches (below cap)', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      repository.countActiveVouches.mockResolvedValue(2);
      repository.confirmRequest.mockResolvedValue('requestee-kc-1');

      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).resolves.toBeUndefined();
    });
  });

  describe('decline', () => {
    it('declines a pending request', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      repository.declineRequest.mockResolvedValue(true);

      await service.decline(REQUEST_ID, VOUCHER_KC_ID);

      expect(repository.declineRequest).toHaveBeenCalledWith(REQUEST_ID, VOUCHER_KC_ID);
      expect(eidService.updateKeycloakEidStatus).not.toHaveBeenCalled();
    });

    it('throws 404 when request not found', async () => {
      repository.getRawRequest.mockResolvedValue(null);
      await expect(service.decline(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(NotFoundException);
    });

    it('throws 409 when request already processed', async () => {
      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'declined' });
      await expect(service.decline(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
    });
  });

  describe('createRequest', () => {
    const createdDto: VouchRequestDto = {
      id: 'new-req-uuid',
      requestedAt: '2026-03-02T10:00:00Z',
      requestee: {
        shareMemberId: identifiedTarget.shareMemberId,
        name: identifiedTarget.name,
        pictureUrl: null,
      },
    };

    it('creates and returns a vouch request', async () => {
      repository.findIdentifiedByEmail.mockResolvedValue(identifiedTarget);
      repository.hasPendingRequest.mockResolvedValue(false);
      repository.createRequest.mockResolvedValue(createdDto);

      const result = await service.createRequest(REQUESTER_KC_ID, 'un_identified', TARGET_EMAIL);

      expect(result).toEqual(createdDto);
      expect(repository.findIdentifiedByEmail).toHaveBeenCalledWith(TARGET_EMAIL);
      expect(repository.hasPendingRequest).toHaveBeenCalledWith(
        REQUESTER_KC_ID,
        identifiedTarget.keycloakId,
      );
      expect(repository.createRequest).toHaveBeenCalledWith(
        REQUESTER_KC_ID,
        identifiedTarget.keycloakId,
        expect.any(String),
      );
    });

    it('throws 400 if requester is already identified', async () => {
      await expect(
        service.createRequest(REQUESTER_KC_ID, 'identified', TARGET_EMAIL),
      ).rejects.toThrow(BadRequestException);
      expect(repository.findIdentifiedByEmail).not.toHaveBeenCalled();
    });

    it('throws 404 if no IDENTIFIED member found with that email', async () => {
      repository.findIdentifiedByEmail.mockResolvedValue(null);

      await expect(
        service.createRequest(REQUESTER_KC_ID, 'un_identified', TARGET_EMAIL),
      ).rejects.toThrow(NotFoundException);
      expect(repository.createRequest).not.toHaveBeenCalled();
    });

    it('throws 409 if a pending request to that member already exists', async () => {
      repository.findIdentifiedByEmail.mockResolvedValue(identifiedTarget);
      repository.hasPendingRequest.mockResolvedValue(true);

      await expect(
        service.createRequest(REQUESTER_KC_ID, 'un_identified', TARGET_EMAIL),
      ).rejects.toThrow(ConflictException);
      expect(repository.createRequest).not.toHaveBeenCalled();
    });
  });

  describe('createInviterRequest', () => {
    it('delegates to repository.maybeCreateInviterRequest', async () => {
      repository.maybeCreateInviterRequest.mockResolvedValue(undefined);

      await service.createInviterRequest('member-kc-1', 'community-1');

      expect(repository.maybeCreateInviterRequest).toHaveBeenCalledWith(
        'member-kc-1',
        'community-1',
        expect.any(String),
      );
    });

    it('does not throw if repository throws (best-effort)', async () => {
      repository.maybeCreateInviterRequest.mockRejectedValue(new Error('Neo4j down'));

      await expect(
        service.createInviterRequest('member-kc-1', 'community-1'),
      ).resolves.toBeUndefined();
    });
  });
});

import { useEffect, useState } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { useAuth } from '../auth/AuthContext'
import { AppShell } from '../components/AppShell'
import { apiFetch, ApiError } from '../api/api'
import { createVouchRequest } from '../api/vouch'

type Phase =
  | { kind: 'idle' }
  | { kind: 'starting' }
  | { kind: 'processing' }
  | { kind: 'success' }
  | { kind: 'error'; message: string }

const STATE_KEY = 'eid_state'

export function VerifyPage(): JSX.Element {
  const { user } = useAuth()
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const [phase, setPhase] = useState<Phase>({ kind: 'idle' })

  // ── Handle return from eID provider ────────────────────────────────
  useEffect(() => {
    const rid = searchParams.get('rid')
    const returnedState = searchParams.get('state')
    const status = searchParams.get('status')

    if (status === 'cancelled') {
      setPhase({ kind: 'error', message: t('verify.error_cancelled') })
      return
    }

    if (!rid || !returnedState || !user) return

    const storedState = sessionStorage.getItem(STATE_KEY)
    if (storedState !== returnedState) {
      setPhase({ kind: 'error', message: t('verify.error_invalid_state') })
      return
    }

    sessionStorage.removeItem(STATE_KEY)
    setPhase({ kind: 'processing' })

    apiFetch<void>('/v2/eid/callback', user.accessToken, {
      method: 'POST',
      body: JSON.stringify({ rid, state: returnedState }),
    })
      .then(() => {
        setPhase({ kind: 'success' })
        setTimeout(() => navigate('/profile', { replace: true }), 2000)
      })
      .catch((err) => {
        if (err instanceof ApiError && err.status === 409) {
          setPhase({ kind: 'error', message: t('verify.error_duplicate') })
        } else {
          setPhase({ kind: 'error', message: t('verify.error_failed') })
        }
      })
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  // ── Start eID flow ─────────────────────────────────────────────────
  const handleStart = async (): Promise<void> => {
    if (!user) return
    setPhase({ kind: 'starting' })
    try {
      const { redirectUrl, state } = await apiFetch<{ redirectUrl: string; state: string }>(
        '/v2/eid/start',
        user.accessToken,
      )
      sessionStorage.setItem(STATE_KEY, state)
      window.location.href = redirectUrl
    } catch {
      setPhase({ kind: 'error', message: t('verify.error_start') })
    }
  }

  if (user?.eidStatus === 'identified' && phase.kind === 'idle') {
    return (
      <AppShell>
        <div className="verify-container">
          <div className="verify-card">
            <div className="verify-icon verify-icon-success">✓</div>
            <h1 className="verify-title">{t('verify.already_verified_title')}</h1>
            <p className="verify-subtitle">{t('verify.already_verified_desc')}</p>
            <button className="cta-button" onClick={() => navigate('/profile')}>
              {t('verify.back_to_profile')}
            </button>
          </div>
        </div>
      </AppShell>
    )
  }

  return (
    <AppShell>
      <div className="verify-container">
        <div className="verify-card">

          {phase.kind === 'processing' && (
            <LoadingState message={t('verify.processing')} />
          )}

          {phase.kind === 'success' && (
            <>
              <div className="verify-icon verify-icon-success">✓</div>
              <h1 className="verify-title">{t('verify.success_title')}</h1>
              <p className="verify-subtitle">{t('verify.success_desc')}</p>
            </>
          )}

          {phase.kind === 'error' && (
            <>
              <div className="verify-icon verify-icon-error">✕</div>
              <h1 className="verify-title">{t('verify.failed_title')}</h1>
              <p className="verify-subtitle">{phase.message}</p>
              <button
                className="cta-button"
                onClick={() => setPhase({ kind: 'idle' })}
              >
                {t('verify.try_again')}
              </button>
            </>
          )}

          {(phase.kind === 'idle' || phase.kind === 'starting') && (
            <>
              <div className="verify-icon verify-icon-neutral">🪪</div>
              <h1 className="verify-title">{t('verify.title')}</h1>
              <p className="verify-subtitle">{t('verify.subtitle')}</p>

              <div className="verify-steps">
                <VerifyStep
                  number={1}
                  title={t('verify.step1_title')}
                  detail={t('verify.step1_detail')}
                />
                <VerifyStep
                  number={2}
                  title={t('verify.step2_title')}
                  detail={t('verify.step2_detail')}
                />
                <VerifyStep
                  number={3}
                  title={t('verify.step3_title')}
                  detail={t('verify.step3_detail')}
                />
              </div>

              <button
                className="cta-button verify-start-btn"
                onClick={() => void handleStart()}
                disabled={phase.kind === 'starting'}
              >
                {phase.kind === 'starting' ? t('verify.starting') : t('verify.start')}
              </button>

              <p className="verify-privacy">{t('verify.privacy')}</p>

              <div className="verify-vouch-divider">
                <span>{t('verify.or_alternatively')}</span>
              </div>

              <VouchRequestForm />
            </>
          )}
        </div>
      </div>
    </AppShell>
  )
}

function VerifyStep({
  number,
  title,
  detail,
}: {
  number: number
  title: string
  detail: string
}): JSX.Element {
  return (
    <div className="verify-step">
      <div className="verify-step-number">{number}</div>
      <div>
        <strong>{title}</strong>
        <p>{detail}</p>
      </div>
    </div>
  )
}

function VouchRequestForm(): JSX.Element {
  const { user } = useAuth()
  const { t } = useTranslation()
  const [email, setEmail] = useState('')
  const [state, setState] = useState<'idle' | 'sending' | 'sent' | 'error_not_found' | 'error_duplicate' | 'error'>('idle')

  const handleSubmit = async (e: React.FormEvent): Promise<void> => {
    e.preventDefault()
    if (!user || !email.trim()) return
    setState('sending')
    try {
      await createVouchRequest(email.trim(), user.accessToken)
      setState('sent')
    } catch (err) {
      if (err instanceof ApiError) {
        if (err.status === 404) setState('error_not_found')
        else if (err.status === 409) setState('error_duplicate')
        else setState('error')
      } else {
        setState('error')
      }
    }
  }

  if (state === 'sent') {
    return (
      <div className="vouch-request-form">
        <p className="vouch-request-sent">✓ {t('verify.vouch_request_sent')}</p>
      </div>
    )
  }

  return (
    <div className="vouch-request-form">
      <p className="vouch-request-label">{t('verify.vouch_request_intro')}</p>
      <form onSubmit={(e) => void handleSubmit(e)} className="vouch-request-row">
        <input
          type="email"
          className="vouch-request-input"
          placeholder={t('verify.vouch_request_placeholder')}
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          disabled={state === 'sending'}
          required
        />
        <button
          type="submit"
          className="nav-btn nav-btn-secondary vouch-request-btn"
          disabled={state === 'sending' || !email.trim()}
        >
          {state === 'sending' ? t('verify.vouch_request_sending') : t('verify.vouch_request_cta')}
        </button>
      </form>
      {state === 'error_not_found' && (
        <p className="vouch-request-error">{t('verify.vouch_error_not_found')}</p>
      )}
      {state === 'error_duplicate' && (
        <p className="vouch-request-error">{t('verify.vouch_error_duplicate')}</p>
      )}
      {state === 'error' && (
        <p className="vouch-request-error">{t('verify.vouch_error_generic')}</p>
      )}
    </div>
  )
}

function LoadingState({ message }: { message: string }): JSX.Element {
  return (
    <div className="verify-loading">
      <div className="verify-spinner" />
      <p>{message}</p>
    </div>
  )
}

import { useEffect, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { useAuth } from '../auth/AuthContext'
import { AppShell } from '../components/AppShell'
import { ApiError } from '../api/api'
import {
  confirmVouch,
  declineVouch,
  fetchVouchRequest,
  type VouchRequest,
} from '../api/vouch'

type PageState =
  | { kind: 'loading' }
  | { kind: 'not_found' }
  | { kind: 'already_processed' }
  | { kind: 'error' }
  | { kind: 'active'; request: VouchRequest }
  | { kind: 'confirmed'; name: string }
  | { kind: 'declined' }

export function VouchPage(): JSX.Element {
  const { requestId } = useParams<{ requestId: string }>()
  const { user } = useAuth()
  const navigate = useNavigate()
  const { t } = useTranslation()
  const [state, setState] = useState<PageState>({ kind: 'loading' })
  const [isActing, setIsActing] = useState(false)

  useEffect(() => {
    if (!user || !requestId) return
    fetchVouchRequest(requestId, user.accessToken)
      .then((req) => setState({ kind: 'active', request: req }))
      .catch((err) => {
        if (err instanceof ApiError && err.status === 404) {
          setState({ kind: 'not_found' })
        } else if (err instanceof ApiError && err.status === 409) {
          setState({ kind: 'already_processed' })
        } else {
          setState({ kind: 'error' })
        }
      })
  }, [user, requestId])

  const handleConfirm = async (): Promise<void> => {
    if (!user || !requestId || state.kind !== 'active') return
    setIsActing(true)
    try {
      await confirmVouch(requestId, user.accessToken)
      setState({ kind: 'confirmed', name: state.request.requestee.name })
    } catch {
      setIsActing(false)
    }
  }

  const handleDecline = async (): Promise<void> => {
    if (!user || !requestId || state.kind !== 'active') return
    setIsActing(true)
    try {
      await declineVouch(requestId, user.accessToken)
      setState({ kind: 'declined' })
    } catch {
      setIsActing(false)
    }
  }

  return (
    <AppShell>
      <div className="vouch-page">
        {state.kind === 'loading' && (
          <div className="vouch-loading">
            <div className="vouch-spinner" />
          </div>
        )}

        {(state.kind === 'not_found' || state.kind === 'already_processed' || state.kind === 'error') && (
          <div className="vouch-card">
            <p className="vouch-info-text">
              {state.kind === 'not_found' && t('vouch.not_found')}
              {state.kind === 'already_processed' && t('vouch.already_processed')}
              {state.kind === 'error' && t('vouch.network_error')}
            </p>
            <button className="cta-button" onClick={() => navigate('/hub')}>
              {t('vouch.back_to_hub')}
            </button>
          </div>
        )}

        {state.kind === 'active' && (
          <div className="vouch-card">
            <VoucheeAvatar
              name={state.request.requestee.name}
              pictureUrl={state.request.requestee.pictureUrl}
            />
            <h1 className="vouch-name">{state.request.requestee.name}</h1>
            <p className="vouch-request-text">{t('vouch.requests_confirmation')}</p>

            <div className="vouch-divider" />

            <p className="vouch-responsibility">{t('vouch.responsibility_statement')}</p>

            <button
              className="cta-button vouch-confirm-btn"
              onClick={() => void handleConfirm()}
              disabled={isActing}
            >
              {isActing ? t('vouch.confirming') : t('vouch.confirm_cta')}
            </button>
            <button
              className="vouch-decline-btn"
              onClick={() => void handleDecline()}
              disabled={isActing}
            >
              {t('vouch.decline_cta')}
            </button>
          </div>
        )}

        {state.kind === 'confirmed' && (
          <div className="vouch-card">
            <VoucheeAvatar name={state.name} pictureUrl={null} />
            <h1 className="vouch-name">{state.name}</h1>
            <p className="vouch-member-identified">
              <span className="vouch-identified-check">✓</span>
              {t('vouch.member_identified')}
            </p>
            <button className="cta-button" onClick={() => navigate('/hub')}>
              {t('vouch.back_to_hub')}
            </button>
          </div>
        )}

        {state.kind === 'declined' && (
          <div className="vouch-card">
            <p className="vouch-info-text">{t('vouch.declined_message')}</p>
            <button className="cta-button" onClick={() => navigate('/hub')}>
              {t('vouch.back_to_hub')}
            </button>
          </div>
        )}
      </div>
    </AppShell>
  )
}

function VoucheeAvatar({
  name,
  pictureUrl,
}: {
  name: string
  pictureUrl: string | null
}): JSX.Element {
  const initials = name
    .split(' ')
    .map((n) => n[0])
    .join('')
    .toUpperCase()
    .slice(0, 2)

  return (
    <div className="vouchee-avatar">
      {pictureUrl ? (
        <img src={pictureUrl} alt={name} className="vouchee-avatar-img" />
      ) : (
        <span className="vouchee-avatar-initials">{initials}</span>
      )}
    </div>
  )
}

import { apiFetch } from './api'

export interface VouchRequest {
  id: string
  requestedAt: string
  requestee: {
    shareMemberId: string
    name: string
    pictureUrl: string | null
  }
}

export function fetchVouchRequest(
  requestId: string,
  accessToken: string,
): Promise<VouchRequest> {
  return apiFetch<VouchRequest>(
    `/v2/sharemember/vouch-requests/${requestId}`,
    accessToken,
  )
}

export function fetchPendingVouchRequests(
  accessToken: string,
): Promise<VouchRequest[]> {
  return apiFetch<VouchRequest[]>(
    '/v2/sharemember/vouch-requests',
    accessToken,
  )
}

export function confirmVouch(requestId: string, accessToken: string): Promise<void> {
  return apiFetch(
    `/v2/sharemember/vouch-requests/${requestId}/confirm`,
    accessToken,
    { method: 'POST' },
  )
}

export function declineVouch(requestId: string, accessToken: string): Promise<void> {
  return apiFetch(
    `/v2/sharemember/vouch-requests/${requestId}/decline`,
    accessToken,
    { method: 'POST' },
  )
}

export function createVouchRequest(
  targetEmail: string,
  accessToken: string,
): Promise<VouchRequest> {
  return apiFetch<VouchRequest>(
    '/v2/sharemember/vouch-requests',
    accessToken,
    {
      method: 'POST',
      body: JSON.stringify({ targetEmail }),
    },
  )
}

