// ── Open (QR-based) vouch requests ──────────────────────────────────

/** Cancel all pending open requests from this requester (idempotent QR regeneration). */
async cancelOpenRequests(requesterKeycloakId: string): Promise<void> {
  await this.neo4j.writeVoid(
    `MATCH (sm:ShareMember {keycloakId: $requesterKeycloakId})<-[:FROM]-(req:VouchRequest {status: 'pending', type: 'open'})
     WHERE NOT (req)-[:TO]->()
     SET req.status = 'cancelled'`,
    { requesterKeycloakId },
  );
}

/** Create an open VouchRequest (no target voucher yet). */
async createOpenRequest(
  requesterKeycloakId: string,
  requestId: string,
): Promise<VouchRequestDto> {
  const results = await this.neo4j.write(
    `MATCH (sm:ShareMember {keycloakId: $requesterKeycloakId})
     CREATE (req:VouchRequest {id: $requestId, requestedAt: datetime(), status: 'pending', type: 'open'})
     CREATE (req)-[:FROM]->(sm)
     RETURN req, sm AS requestee`,
    { requesterKeycloakId, requestId },
    (record) => this.mapRequest(record),
  );
  return results[0];
}

/** Fetch an unclaimed open request (no voucher assigned). */
async getOpenRequest(
  requestId: string,
): Promise<RawVouchRequest | null> {
  return this.neo4j.querySingleObject(
    `MATCH (req:VouchRequest {id: $requestId})-[:FROM]->(requestee:ShareMember)
     WHERE NOT (req)-[:TO]->()
     RETURN req, requestee`,
    { requestId },
    (record) => ({
      ...this.mapRequest(record),
      status: (record.get('req') as Node).properties['status'] as RawVouchRequest['status'],
    }),
  );
}

/**
 * Atomically assign a voucher to an open request.
 * Returns the DTO if successful, null if the request was already claimed or voucher = requestee.
 */
async claimOpenRequest(
  requestId: string,
  voucherKeycloakId: string,
): Promise<VouchRequestDto | null> {
  return this.neo4j.querySingleObject(
    `MATCH (req:VouchRequest {id: $requestId, status: 'pending'})-[:FROM]->(requestee:ShareMember)
     WHERE NOT (req)-[:TO]->()
     MATCH (voucher:ShareMember {keycloakId: $voucherKeycloakId})
     WHERE voucher <> requestee
     CREATE (req)-[:TO]->(voucher)
     RETURN req, requestee`,
    { requestId, voucherKeycloakId },
    (record) => this.mapRequest(record),
  );
}

/** Get request status — for polling from the requestee's QR screen. */
async getRequestStatus(
  requestId: string,
  requesterKeycloakId: string,
): Promise<string | null> {
  return this.neo4j.querySingleObject(
    `MATCH (sm:ShareMember {keycloakId: $requesterKeycloakId})<-[:FROM]-(req:VouchRequest {id: $requestId})
     RETURN req.status AS status`,
    { requestId, requesterKeycloakId },
    (record) => record.get('status') as string,
  );
}

