    private readonly eidService: EidService,
  ) {}

  async getPendingRequests(voucherKeycloakId: string): Promise<VouchRequestDto[]> {
    return this.repository.getPendingRequests(voucherKeycloakId);
  }

  async getRequest(
    requestId: string,
    voucherKeycloakId: string,
    voucherEidStatus?: string,
  ): Promise<VouchRequestDto> {
    // Try targeted lookup first (existing path)
    const raw = await this.repository.getRawRequest(requestId, voucherKeycloakId);
    if (raw) {
      if (raw.status !== 'pending') throw new ConflictException('Vouch request already processed.');
      return { id: raw.id, requestedAt: raw.requestedAt, requestee: raw.requestee };
    }

    // Fallback: try open (QR-based) request
    const open = await this.repository.getOpenRequest(requestId);
    if (!open) throw new NotFoundException('Vouch request not found.');
    if (open.status !== 'pending') throw new ConflictException('Vouch request already processed.');

    if (voucherEidStatus !== 'identified') {
      throw new ForbiddenException('Only IDENTIFIED members can vouch for others.');
    }

    const claimed = await this.repository.claimOpenRequest(requestId, voucherKeycloakId);
    if (!claimed) {
      throw new BadRequestException('Cannot vouch for yourself.');
    }

    return { id: claimed.id, requestedAt: claimed.requestedAt, requestee: claimed.requestee };
  }

  async confirm(requestId: string, voucherKeycloakId: string): Promise<void> {
    const raw = await this.repository.getRawRequest(requestId, voucherKeycloakId);
    if (!raw) throw new NotFoundException('Vouch request not found.');
    if (raw.status !== 'pending') throw new ConflictException('Vouch request already processed.');

    const activeCount = await this.repository.countActiveVouches(voucherKeycloakId);
    if (activeCount >= MAX_ACTIVE_VOUCHES) {
      throw new ForbiddenException(
        `Maximum active vouches reached (${MAX_ACTIVE_VOUCHES}). You must wait for an existing vouch to be superseded before confirming another.`,
      );
    }

    const vouchId = crypto.randomUUID();
    const requesteeKeycloakId = await this.repository.confirmRequest(
      requestId,
      voucherKeycloakId,
      vouchId,
    );

    if (requesteeKeycloakId) {
      // Best-effort: update Keycloak so the next token refresh includes eid_status = identified
      await this.eidService.updateKeycloakEidStatus(requesteeKeycloakId);
    } else {
      this.logger.warn(
        `confirm: request ${requestId} was valid but write returned no rows (concurrent confirm?)`,
      );
    }
  }

  async decline(requestId: string, voucherKeycloakId: string): Promise<void> {
    const raw = await this.repository.getRawRequest(requestId, voucherKeycloakId);
    if (!raw) throw new NotFoundException('Vouch request not found.');
    if (raw.status !== 'pending') throw new ConflictException('Vouch request already processed.');

    await this.repository.declineRequest(requestId, voucherKeycloakId);
  }

  async createRequest(
    requesterKeycloakId: string,
    requesterEidStatus: string | undefined,
    targetEmail: string,
  ): Promise<VouchRequestDto> {
    if (requesterEidStatus === 'identified') {
      throw new BadRequestException('Already identified — vouching not needed.');
    }

    const target = await this.repository.findIdentifiedByEmail(targetEmail);
    if (!target) {
      throw new NotFoundException('No IDENTIFIED member found with that email.');
    }

    const alreadyPending = await this.repository.hasPendingRequest(
      requesterKeycloakId,
      target.keycloakId,
    );
    if (alreadyPending) {
      throw new ConflictException('A pending vouch request to this member already exists.');
    }

    const requestId = crypto.randomUUID();
    return this.repository.createRequest(requesterKeycloakId, target.keycloakId, requestId);
  }

  async createInviterRequest(newMemberKeycloakId: string, communityId: string): Promise<void> {
    try {
      const requestId = crypto.randomUUID();
      await this.repository.maybeCreateInviterRequest(newMemberKeycloakId, communityId, requestId);
    } catch (err) {
      this.logger.warn(
        `createInviterRequest: best-effort failed for member ${newMemberKeycloakId} in community ${communityId}: ${String(err)}`,
      );
    }
  }
}

