import {
  Body,
  Controller,
  Get,
  HttpCode,
  HttpStatus,
  Param,
  Post,
  UseGuards,
} from '@nestjs/common';
import { IsEmail, IsNotEmpty } from 'class-validator';
import { KeycloakAuthGuard } from '../common/guards/keycloak-auth.guard';
import { CurrentUser } from '../common/decorators/current-user.decorator';
import * as SharememberTypes from '../common/interfaces/sharemember-token.interface';
type SharememberToken = SharememberTypes.SharememberToken;
import { VouchService } from './vouch.service';
import { VouchRequestDto } from './dto/vouch-request.dto';

class CreateVouchRequestBody {
  @IsEmail()
  @IsNotEmpty()
  targetEmail!: string;
}

/**
 * Peer vouching endpoints — identity layer, not community-scoped.
 * Addressed to the IDENTIFIED member who is asked to confirm another's identity.
 */
@Controller('v2/sharemember/vouch-requests')
@UseGuards(KeycloakAuthGuard)
export class VouchController {
  constructor(private readonly service: VouchService) {}

  /** POST /v2/sharemember/vouch-requests — create a vouch request by target email */
  @Post()
  @HttpCode(HttpStatus.CREATED)
  async createRequest(
    @Body() body: CreateVouchRequestBody,
    @CurrentUser() user: SharememberToken,
  ): Promise<VouchRequestDto> {
    return this.service.createRequest(user.sub, user.eid_status, body.targetEmail);
  }

  /** GET /v2/sharemember/vouch-requests — pending requests addressed to me */
  @Get()
  async getPendingRequests(
    @CurrentUser() user: SharememberToken,
  ): Promise<VouchRequestDto[]> {
    return this.service.getPendingRequests(user.sub);
  }

  /** GET /v2/sharemember/vouch-requests/:requestId — single request addressed to me */
  @Get(':requestId')
  async getRequest(
    @Param('requestId') requestId: string,
    @CurrentUser() user: SharememberToken,
  ): Promise<VouchRequestDto> {
    return this.service.getRequest(requestId, user.sub);
  }

  /** POST /v2/sharemember/vouch-requests/:requestId/confirm — confirm identity */
  @Post(':requestId/confirm')
  @HttpCode(HttpStatus.NO_CONTENT)
  async confirm(
    @Param('requestId') requestId: string,
    @CurrentUser() user: SharememberToken,
  ): Promise<void> {
    return this.service.confirm(requestId, user.sub);
  }

  /** POST /v2/sharemember/vouch-requests/:requestId/decline — decline request */
  @Post(':requestId/decline')
  @HttpCode(HttpStatus.NO_CONTENT)
  async decline(
    @Param('requestId') requestId: string,
    @CurrentUser() user: SharememberToken,
  ): Promise<void> {
    return this.service.decline(requestId, user.sub);
  }
}

