      expect(repository.maybeCreateInviterRequest).toHaveBeenCalledWith(
        'member-kc-1',
        'community-1',
        expect.any(String),
      );
    });

    it('does not throw if repository throws (best-effort)', async () => {
      repository.maybeCreateInviterRequest.mockRejectedValue(new Error('Neo4j down'));

      await expect(
        service.createInviterRequest('member-kc-1', 'community-1'),
      ).resolves.toBeUndefined();
    });
  });
});

import {
  BadRequestException,
  ConflictException,
  ForbiddenException,
  NotFoundException,
} from '@nestjs/common';
import { EidService } from '../eid/eid.service';
import { VouchRepository } from './vouch.repository';
import { VouchService } from './vouch.service';
import { VouchRequestDto } from './dto/vouch-request.dto';

const VOUCHER_KC_ID = 'voucher-kc-1';
const REQUESTER_KC_ID = 'requester-kc-1';
const REQUEST_ID = 'req-uuid-1';
const TARGET_EMAIL = 'anna@example.com';

const identifiedTarget = {
  keycloakId: 'target-kc-1',
  shareMemberId: 'sm-target-1',
  name: 'Anna Weber',
};

const pendingRequest = {
  id: REQUEST_ID,
  requestedAt: '2026-03-01T10:00:00Z',
  status: 'pending' as const,
  requestee: {
    shareMemberId: 'sm-requestee-1',
    name: 'Anna Weber',
    pictureUrl: null,
  },
};

const pendingDto: VouchRequestDto = {
  id: pendingRequest.id,
  requestedAt: pendingRequest.requestedAt,
  requestee: pendingRequest.requestee,
};

describe('VouchService', () => {
  let service: VouchService;
  let repository: jest.Mocked<VouchRepository>;
  let eidService: jest.Mocked<Pick<EidService, 'updateKeycloakEidStatus'>>;

  beforeEach(() => {
    repository = {
      getPendingRequests: jest.fn(),
      getRawRequest: jest.fn(),
      countActiveVouches: jest.fn(),
      confirmRequest: jest.fn(),
      declineRequest: jest.fn(),
      findIdentifiedByEmail: jest.fn(),
      hasPendingRequest: jest.fn(),
      createRequest: jest.fn(),
      maybeCreateInviterRequest: jest.fn(),
    } as unknown as jest.Mocked<VouchRepository>;

    eidService = {
      updateKeycloakEidStatus: jest.fn().mockResolvedValue(undefined),
    } as unknown as jest.Mocked<Pick<EidService, 'updateKeycloakEidStatus'>>;

    service = new VouchService(repository, eidService as unknown as EidService);
  });

  describe('getPendingRequests', () => {
    it('delegates to repository', async () => {
      repository.getPendingRequests.mockResolvedValue([pendingDto]);
      const result = await service.getPendingRequests(VOUCHER_KC_ID);
      expect(result).toEqual([pendingDto]);
      expect(repository.getPendingRequests).toHaveBeenCalledWith(VOUCHER_KC_ID);
    });

    it('returns empty array when no pending requests', async () => {
      repository.getPendingRequests.mockResolvedValue([]);
      expect(await service.getPendingRequests(VOUCHER_KC_ID)).toEqual([]);
    });
  });

  describe('getRequest', () => {
    it('returns DTO for a pending request', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      const result = await service.getRequest(REQUEST_ID, VOUCHER_KC_ID);
      expect(result.id).toBe(REQUEST_ID);
      expect(result.requestee.name).toBe('Anna Weber');
    });

    it('throws 404 when request not found', async () => {
      repository.getRawRequest.mockResolvedValue(null);
      await expect(service.getRequest(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(NotFoundException);
    });

    it('throws 409 when request already confirmed', async () => {
      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'confirmed' });
      await expect(service.getRequest(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
    });

    it('throws 409 when request already declined', async () => {
      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'declined' });
      await expect(service.getRequest(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
    });
  });

  describe('confirm', () => {
    it('confirms a pending request and triggers Keycloak update', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      repository.countActiveVouches.mockResolvedValue(0);
      repository.confirmRequest.mockResolvedValue('requestee-kc-1');

      await service.confirm(REQUEST_ID, VOUCHER_KC_ID);

      expect(repository.confirmRequest).toHaveBeenCalledWith(
        REQUEST_ID,
        VOUCHER_KC_ID,
        expect.any(String),
      );
      expect(eidService.updateKeycloakEidStatus).toHaveBeenCalledWith('requestee-kc-1');
    });

    it('throws 404 when request not found', async () => {
      repository.getRawRequest.mockResolvedValue(null);
      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(NotFoundException);
      expect(repository.confirmRequest).not.toHaveBeenCalled();
    });

    it('throws 409 when request already processed', async () => {
      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'confirmed' });
      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
    });

    it('throws 403 when voucher has reached 3 active vouches', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      repository.countActiveVouches.mockResolvedValue(3);

      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ForbiddenException);
      expect(repository.confirmRequest).not.toHaveBeenCalled();
    });

    it('allows confirm at exactly 2 active vouches (below cap)', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      repository.countActiveVouches.mockResolvedValue(2);
      repository.confirmRequest.mockResolvedValue('requestee-kc-1');

      await expect(service.confirm(REQUEST_ID, VOUCHER_KC_ID)).resolves.toBeUndefined();
    });
  });

  describe('decline', () => {
    it('declines a pending request', async () => {
      repository.getRawRequest.mockResolvedValue(pendingRequest);
      repository.declineRequest.mockResolvedValue(true);

      await service.decline(REQUEST_ID, VOUCHER_KC_ID);

      expect(repository.declineRequest).toHaveBeenCalledWith(REQUEST_ID, VOUCHER_KC_ID);
      expect(eidService.updateKeycloakEidStatus).not.toHaveBeenCalled();
    });

    it('throws 404 when request not found', async () => {
      repository.getRawRequest.mockResolvedValue(null);
      await expect(service.decline(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(NotFoundException);
    });

    it('throws 409 when request already processed', async () => {
      repository.getRawRequest.mockResolvedValue({ ...pendingRequest, status: 'declined' });
      await expect(service.decline(REQUEST_ID, VOUCHER_KC_ID)).rejects.toThrow(ConflictException);
    });
  });

  describe('createRequest', () => {
    const createdDto: VouchRequestDto = {
      id: 'new-req-uuid',
      requestedAt: '2026-03-02T10:00:00Z',
      requestee: {
        shareMemberId: identifiedTarget.shareMemberId,
        name: identifiedTarget.name,
        pictureUrl: null,
      },
    };

    it('creates and returns a vouch request', async () => {
      repository.findIdentifiedByEmail.mockResolvedValue(identifiedTarget);
      repository.hasPendingRequest.mockResolvedValue(false);
      repository.createRequest.mockResolvedValue(createdDto);

      const result = await service.createRequest(REQUESTER_KC_ID, 'un_identified', TARGET_EMAIL);

      expect(result).toEqual(createdDto);
      expect(repository.findIdentifiedByEmail).toHaveBeenCalledWith(TARGET_EMAIL);
      expect(repository.hasPendingRequest).toHaveBeenCalledWith(
        REQUESTER_KC_ID,
        identifiedTarget.keycloakId,
      );
      expect(repository.createRequest).toHaveBeenCalledWith(
        REQUESTER_KC_ID,
        identifiedTarget.keycloakId,
        expect.any(String),
      );
    });

    it('throws 400 if requester is already identified', async () => {
      await expect(
        service.createRequest(REQUESTER_KC_ID, 'identified', TARGET_EMAIL),
      ).rejects.toThrow(BadRequestException);
      expect(repository.findIdentifiedByEmail).not.toHaveBeenCalled();
    });

    it('throws 404 if no IDENTIFIED member found with that email', async () => {
      repository.findIdentifiedByEmail.mockResolvedValue(null);

      await expect(
        service.createRequest(REQUESTER_KC_ID, 'un_identified', TARGET_EMAIL),
      ).rejects.toThrow(NotFoundException);
      expect(repository.createRequest).not.toHaveBeenCalled();
    });

    it('throws 409 if a pending request to that member already exists', async () => {
      repository.findIdentifiedByEmail.mockResolvedValue(identifiedTarget);
      repository.hasPendingRequest.mockResolvedValue(true);

      await expect(
        service.createRequest(REQUESTER_KC_ID, 'un_identified', TARGET_EMAIL),
      ).rejects.toThrow(ConflictException);
      expect(repository.createRequest).not.toHaveBeenCalled();
    });
  });

  describe('createOpenRequest', () => {
    const openDto: VouchRequestDto = {
      id: 'open-req-uuid',
      requestedAt: '2026-03-02T10:00:00Z',
      requestee: {
        shareMemberId: 'sm-requestee-1',
        name: 'Max Müller',
        pictureUrl: null,
      },
    };

    it('creates an open request and cancels existing ones', async () => {
      repository.cancelOpenRequests.mockResolvedValue(undefined);
      repository.createOpenRequest.mockResolvedValue(openDto);

      const result = await service.createOpenRequest(REQUESTER_KC_ID, 'un_identified');

      expect(result).toEqual(openDto);
      expect(repository.cancelOpenRequests).toHaveBeenCalledWith(REQUESTER_KC_ID);
      expect(repository.createOpenRequest).toHaveBeenCalledWith(REQUESTER_KC_ID, expect.any(String));
    });

    it('throws 400 if requester is already identified', async () => {
      await expect(
        service.createOpenRequest(REQUESTER_KC_ID, 'identified'),
      ).rejects.toThrow(BadRequestException);
      expect(repository.cancelOpenRequests).not.toHaveBeenCalled();
    });
  });

  describe('getRequest — open request fallback', () => {
    const openRaw = {
      ...pendingRequest,
      status: 'pending' as const,
    };

    it('auto-claims open request for IDENTIFIED voucher', async () => {
      repository.getRawRequest.mockResolvedValue(null); // targeted lookup misses
      repository.getOpenRequest.mockResolvedValue(openRaw);
      repository.claimOpenRequest.mockResolvedValue(pendingDto);

      const result = await service.getRequest(REQUEST_ID, VOUCHER_KC_ID, 'identified');

      expect(result.id).toBe(REQUEST_ID);
      expect(repository.claimOpenRequest).toHaveBeenCalledWith(REQUEST_ID, VOUCHER_KC_ID);
    });

    it('rejects UN-IDENTIFIED voucher with 403', async () => {
      repository.getRawRequest.mockResolvedValue(null);
      repository.getOpenRequest.mockResolvedValue(openRaw);

      await expect(
        service.getRequest(REQUEST_ID, VOUCHER_KC_ID, 'un_identified'),
      ).rejects.toThrow(ForbiddenException);
      expect(repository.claimOpenRequest).not.toHaveBeenCalled();
    });

    it('rejects self-vouch with 400', async () => {
      repository.getRawRequest.mockResolvedValue(null);
      repository.getOpenRequest.mockResolvedValue(openRaw);
      repository.claimOpenRequest.mockResolvedValue(null); // self-vouch → null

      await expect(
        service.getRequest(REQUEST_ID, VOUCHER_KC_ID, 'identified'),
      ).rejects.toThrow(BadRequestException);
    });
  });

  describe('getRequestStatus', () => {
    it('returns status for a valid request', async () => {
      repository.getRequestStatus.mockResolvedValue('pending');
      const result = await service.getRequestStatus(REQUEST_ID, REQUESTER_KC_ID);
      expect(result).toEqual({ status: 'pending' });
    });

    it('throws 404 when request not found', async () => {
      repository.getRequestStatus.mockResolvedValue(null);
      await expect(
        service.getRequestStatus(REQUEST_ID, REQUESTER_KC_ID),
      ).rejects.toThrow(NotFoundException);
    });
  });

  describe('createInviterRequest', () => {
    it('delegates to repository.maybeCreateInviterRequest', async () => {
      repository.maybeCreateInviterRequest.mockResolvedValue(undefined);

      await service.createInviterRequest('member-kc-1', 'community-1');

      expect(repository.maybeCreateInviterRequest).toHaveBeenCalledWith(
        'member-kc-1',
        'community-1',
        expect.any(String),
      );
    });

    it('does not throw if repository throws (best-effort)', async () => {
      repository.maybeCreateInviterRequest.mockRejectedValue(new Error('Neo4j down'));

      await expect(
        service.createInviterRequest('member-kc-1', 'community-1'),
      ).resolves.toBeUndefined();
    });
  });
});

