}

.hero-quote {
  max-width: 60rem;
  margin: 4rem auto 0;
  padding: 0 1.5rem;
}

.hero-quote blockquote {
  font-size: 1.25rem;
  font-style: italic;
  margin-bottom: 1rem;
  line-height: 1.8;
}

.hero-quote cite a {
  color: rgba(255, 255, 255, 0.9);
  text-decoration: underline;
  transition: color 0.2s;
}

.hero-quote cite a:hover {
  color: #FF3B2F;
}

/* Content Sections */
.section {
  padding: 4rem 0;

}

.section-alt {
  background-color: #f9fafb;
}

.section-content {
  max-width: 64rem;
  margin: 0 auto;
