}

.red {
  color: #FF3B2F;
}

/* Scroll Indicator */
.scroll-indicator {
  position: absolute;
  bottom: 2rem;
  left: 50%;
  transform: translateX(-50%);
  z-index: 10;
  animation: bounce 2s infinite;
}

.scroll-indicator svg {
  color: white;
  opacity: 0.7;
  transition: opacity 0.2s;
}

.scroll-indicator:hover svg {
  opacity: 1;
}

@keyframes bounce {
  0%, 100% {
    transform: translateX(-50%) translateY(0);
  }
  50% {
    transform: translateX(-50%) translateY(-10px);
  }
}

/* ── AppShell ──────────────────────────────────────────────────────── */

