  }

  .section-text {
    font-size: 1rem;
  }
}

@media (min-width: 768px) {
  .hero-title {
    font-size: 6rem;
  }

  .hero-quote blockquote {
    font-size: 1.5rem;
  }

  .section-title {
    font-size: 2.5rem;
  }
}

/* ── Language Switcher ─────────────────────────────────────────────── */

.lang-switcher {
  position: relative;
}

.lang-switcher-btn {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  background: transparent;
  border: none;
  color: rgba(255, 255, 255, 0.85);
  cursor: pointer;
  font-size: 0.875rem;
  font-weight: 500;
  padding: 0.25rem 0.4rem;
  border-radius: 0.375rem;
  transition: color 0.2s, background-color 0.2s;
}

.lang-switcher-btn:hover {
  color: white;
  background-color: rgba(255, 255, 255, 0.08);
}

.lang-switcher-menu {
  position: absolute;
  top: calc(100% + 0.5rem);
  right: 0;
  background-color: #1e2a4a;
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 0.5rem;
  list-style: none;
  margin: 0;
  padding: 0.25rem 0;
  min-width: 130px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.5);
  z-index: 200;
}

.lang-switcher-item {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.5rem 1rem;
  font-size: 0.9rem;
  color: rgba(255, 255, 255, 0.8);
  cursor: pointer;
  transition: background-color 0.15s;
}

.lang-switcher-item:hover {
  background-color: rgba(255, 255, 255, 0.07);
  color: white;
}

.lang-switcher-item-active {
  color: white;
  font-weight: 500;
}

.lang-switcher-check {
  width: 1rem;
  font-size: 0.75rem;
  color: #FF3B2F;
  flex-shrink: 0;
}

/* ── Verify page ───────────────────────────────────────────────────── */

.verify-container {
  display: flex;
  justify-content: center;
  padding: 3rem 1.5rem;
}

.verify-card {
  background-color: #18203a;
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 0.75rem;
  padding: 2.5rem;
  width: 100%;
  max-width: 560px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1.25rem;
  text-align: center;
}

.verify-icon {
  font-size: 2.5rem;
  width: 72px;
  height: 72px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
}

.verify-icon-success {
  background-color: rgba(74, 222, 128, 0.15);
  color: #4ade80;
  border: 2px solid rgba(74, 222, 128, 0.4);
}

.verify-icon-error {
  background-color: rgba(225, 8, 20, 0.15);
  color: var(--sm-color-primary-red);
  border: 2px solid rgba(225, 8, 20, 0.4);
}

.verify-icon-neutral {
  background-color: rgba(255,255,255,0.06);
  border: 2px solid rgba(255,255,255,0.12);
}

.verify-title {
  font-size: 1.5rem;
  font-weight: bold;
}

.verify-subtitle {
  color: rgba(255,255,255,0.65);
  font-size: 0.95rem;
  line-height: 1.6;
  max-width: 420px;
}

.verify-steps {
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 1rem;
  margin: 0.5rem 0;
  text-align: left;
}

.verify-step {
  display: flex;
  gap: 1rem;
  align-items: flex-start;
  background-color: rgba(255,255,255,0.04);
  border-radius: 0.5rem;
  padding: 1rem;
}

.verify-step-number {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  background-color: var(--sm-color-primary-red);
  color: white;
  font-size: 0.875rem;
  font-weight: bold;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.verify-step strong {
  display: block;
  font-size: 0.9rem;
  margin-bottom: 0.25rem;
}

.verify-step p {
  font-size: 0.8rem;
  color: rgba(255,255,255,0.55);
  line-height: 1.5;
}

.verify-start-btn {
  width: 100%;
  padding: 0.875rem;
  font-size: 1rem;
}

.verify-privacy {
  font-size: 0.75rem;
  color: rgba(255,255,255,0.35);
  line-height: 1.5;
  max-width: 380px;
}

.verify-loading {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1rem;
  padding: 1.5rem 0;
  color: rgba(255,255,255,0.65);
}

.verify-spinner {
  width: 40px;
  height: 40px;
  border: 3px solid rgba(255,255,255,0.1);
  border-top-color: var(--sm-color-primary-red);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

